class APMInstrumentation:
    """Custom APM instrumentation utilities for detailed monitoring."""
    
    @staticmethod
    def trace_function(name: str = None, span_type: str = 'code.custom'):
        """Decorator to trace function execution as APM spans."""
        def decorator(func: Callable) -> Callable:
            @functools.wraps(func)
            def wrapper(*args, **kwargs):
                span_name = name or f"{func.__module__}.{func.__qualname__}"
                client = elasticapm.get_client()
                
                if client:
                    with elasticapm.capture_span(
                        span_name,
                        span_type=span_type,
                        extra={
                            'args_count': len(args),
                            'kwargs_keys': list(kwargs.keys()),
                        }
                    ):
                        try:
                            result = func(*args, **kwargs)
                            return result
                        except Exception as e:
                            elasticapm.capture_exception()
                            raise
                else:
                    return func(*args, **kwargs)
            return wrapper
        return decorator
    
    @staticmethod
    @contextmanager
    def trace_block(name: str, span_type: str = 'code.custom', labels: Dict = None):
        """Context manager to trace a code block as an APM span."""
        with elasticapm.capture_span(name, span_type=span_type, labels=labels or {}):
            start_time = time.time()
            try:
                yield
            except Exception:
                elasticapm.capture_exception()
                raise
            finally:
                duration = time.time() - start_time
                logger.info(f"Block '{name}' completed in {duration:.4f}s")
    
    @staticmethod
    def set_custom_context(data: Dict[str, Any]):
        """Set custom context data on the current transaction."""
        elasticapm.set_custom_context(data)
    
    @staticmethod
    def set_user_context(user_id: str = None, email: str = None, username: str = None):
        """Set user context on the current transaction."""
        elasticapm.set_user_context(
            user_id=user_id,
            email=email,
            username=username
        )
    
    @staticmethod
    def tag_transaction(**tags):
        """Add labels/tags to the current transaction."""
        elasticapm.label(**tags)
    
    @staticmethod
    def capture_message(message: str, param_message: Dict = None):
        """Capture a custom message in APM."""
        client = elasticapm.get_client()
        if client:
            client.capture_message(message, param_message=param_message)


class QueryTracker:
    """Track and log SQL queries for APM monitoring."""
    
    def __init__(self):
        self.queries: List[Dict] = []
        self._enabled = True
    
    def record_query(self, statement: str, parameters: Any, duration: float):
        """Record a SQL query execution."""
        query_info = {
            'statement': str(statement),
            'parameters': str(parameters) if parameters else None,
            'duration_ms': round(duration * 1000, 2),
            'timestamp': datetime.utcnow().isoformat(),
            'stack_trace': traceback.format_stack()[-5:-1]  # Last 4 frames
        }
        self.queries.append(query_info)
        
        # Log slow queries
        if duration > 0.1:  # 100ms threshold
            logger.warning(
                f"Slow query detected ({query_info['duration_ms']}ms): "
                f"{statement[:200]}"
            )
            elasticapm.label(slow_query=True)
    
    def get_summary(self) -> Dict:
        """Get query execution summary."""
        if not self.queries:
            return {'total_queries': 0, 'total_duration_ms': 0}
        
        total_duration = sum(q['duration_ms'] for q in self.queries)
        return {
            'total_queries': len(self.queries),
            'total_duration_ms': round(total_duration, 2),
            'avg_duration_ms': round(total_duration / len(self.queries), 2),
            'slowest_query_ms': max(q['duration_ms'] for q in self.queries),
        }
    
    def reset(self):
        """Reset query tracking."""
        self.queries.clear()


# Global query tracker
query_tracker = QueryTracker()


