def _setup_query_tracking(db: SQLAlchemy):
    """Set up SQLAlchemy event listeners for query performance tracking."""
    from sqlalchemy import event
    
    @event.listens_for(db.engine, "before_cursor_execute")
    def before_cursor_execute(conn, cursor, statement, parameters, context, executemany):
        conn.info.setdefault('query_start_time', []).append(time.time())
    
    @event.listens_for(db.engine, "after_cursor_execute")
    def after_cursor_execute(conn, cursor, statement, parameters, context, executemany):
        total = time.time() - conn.info['query_start_time'].pop(-1)
        query_tracker.record_query(statement, parameters, total)


def _register_middleware(app: Flask):
    """Register request/response middleware for APM context."""
    
    @app.before_request
    def before_request():
        """Capture request start time and set APM context."""
        g.request_start_time = time.time()
        g.request_id = request.headers.get('X-Request-ID', '')
        
        # Reset query tracker for new request
        query_tracker.reset()
        
        # Set custom context with full request data
        request_data = {
            'request_id': g.request_id,
            'method': request.method,
            'url': request.url,
            'remote_addr': request.remote_addr,
            'content_type': request.content_type,
            'content_length': request.content_length,
            'user_agent': str(request.user_agent),
        }
        
        # Capture request body
        if request.is_json:
            try:
                request_data['body'] = request.get_json(silent=True)
            except Exception:
                request_data['body'] = '<unable to parse>'
        elif request.form:
            request_data['body'] = dict(request.form)
        
        # Capture request headers (sanitized)
        sanitized_headers = {}
        sensitive_headers = {'authorization', 'cookie', 'x-api-key', 'x-auth-token'}
        for key, value in request.headers:
            key_lower = key.lower()
            if key_lower in sensitive_headers:
                sanitized_headers[key] = '[REDACTED]'
            else:
                sanitized_headers[key] = value
        request_data['headers'] = sanitized_headers
        
        APMInstrumentation.set_custom_context({
            'request': request_data,
            'timestamp': datetime.utcnow().isoformat(),
        })
        
        # Set transaction labels
        APMInstrumentation.tag_transaction(
            request_id=g.request_id,
            endpoint=request.endpoint or 'unknown',
        )
    
    @app.after_request
    def after_request(response: Response) -> Response:
        """Capture response data and performance metrics."""
        duration = time.time() - g.get('request_start_time', time.time())
        
        # Capture response context
        response_data = {
            'status_code': response.status_code,
            'content_type': response.content_type,
            'content_length': response.content_length,
            'duration_ms': round(duration * 1000, 2),
        }
        
        # Capture response headers
        response_data['headers'] = dict(response.headers)
        
        # Capture response body for JSON responses
        if response.content_type and 'json' in response.content_type:
            try:
                response_data['body'] = json.loads(response.get_data(as_text=True))
            except (json.JSONDecodeError, Exception):
                response_data['body'] = '<unable to parse>'
        
        # Add query summary
        response_data['query_summary'] = query_tracker.get_summary()
        
        # Update custom context with response data
        APMInstrumentation.set_custom_context({
            'response': response_data,
            'performance': {
                'total_duration_ms': response_data['duration_ms'],
                'db_duration_ms': query_tracker.get_summary().get('total_duration_ms', 0),
                'query_count': query_tracker.get_summary().get('total_queries', 0),
            }
        })
        
        # Tag slow requests
        if duration > 1.0:  # 1 second threshold
            APMInstrumentation.tag_transaction(slow_request=True)
            logger.warning(
                f"Slow request: {request.method} {request.path} "
                f"took {duration:.3f}s"
            )
        
        # Add custom response headers
        response.headers['X-Request-Duration-Ms'] = str(round(duration * 1000, 2))
        response.headers['X-Query-Count'] = str(
            query_tracker.get_summary().get('total_queries', 0)
        )
        
        return response


def _register_error_handlers(app: Flask):
    """Register error handlers with APM capture."""
    
    @app.errorhandler(400)
    def bad_request(error):
        elasticapm.label(error_type='bad_request')
        return jsonify({
            'error': 'Bad Request',
            'message': str(error),
            'status_code': 400,
        }), 400
    
    @app.errorhandler(404)
    def not_found(error):
        elasticapm.label(error_type='not_found')
        return jsonify({
            'error': 'Not Found',
            'message': str(error),
            'status_code': 404,
        }), 404
    
    @app.errorhandler(500)
    def internal_error(error):
        elasticapm.capture_exception()
        elasticapm.label(error_type='internal_server_error')
        return jsonify({
            'error': 'Internal Server Error',
            'message': 'An unexpected error occurred',
            'status_code': 500,
            'stack_trace': traceback.format_exc() if app.debug else None,
        }), 500
    
    @app.errorhandler(Exception)
    def handle_exception(error):
        elasticapm.capture_exception()
        elasticapm.label(
            error_type=type(error).__name__,
            error_message=str(error),
        )
        logger.exception(f"Unhandled exception: {error}")
        return jsonify({
            'error': type(error).__name__,
            'message': str(error),
            'status_code': 500,
            'stack_trace': traceback.format_exc() if app.debug else None,
        }), 500


