class UserService:
    """User service with APM instrumentation."""
    
    def __init__(self, db):
        self.db = db
    
    @APMInstrumentation.trace_function(name='UserService.create_user')
    def create_user(self, username: str, email: str) -> Dict:
        """Create a new user."""
        user = self.db.User(username=username, email=email)
        self.db.session.add(user)
        self.db.session.commit()
        
        APMInstrumentation.set_user_context(
            user_id=str(user.id),
            email=user.email,
            username=user.username,
        )
        
        return user.to_dict()
    
    @APMInstrumentation.trace_function(name='UserService.get_user')
    def get_user(self, user_id: int) -> Optional[Dict]:
        """Get user by ID."""
        user = self.db.User.query.get(user_id)
        if user:
            APMInstrumentation.set_user_context(
                user_id=str(user.id),
                email=user.email,
                username=user.username,
            )
            return user.to_dict()
        return None
    
    @APMInstrumentation.trace_function(name='UserService.list_users')
    def list_users(self, page: int = 1, per_page: int = 20) -> Dict:
        """List users with pagination."""
        pagination = self.db.User.query.order_by(
            self.db.User.created_at.desc()
        ).paginate(page=page, per_page=per_page, error_out=False)
        
        return {
            'users': [u.to_dict() for u in pagination.items],
            'total': pagination.total,
            'page': page,
            'per_page': per_page,
            'pages': pagination.pages,
        }


class ProductService:
    """Product service with APM instrumentation."""
    
    def __init__(self, db):
        self.db = db
    
    @APMInstrumentation.trace_function(name='ProductService.create_product')
    def create_product(self, name: str, price: float, stock: int, category: str = None) -> Dict:
        """Create a new product."""
        product = self.db.Product(
            name=name, price=price, stock=stock, category=category
        )
        self.db.session.add(product)
        self.db.session.commit()
        return product.to_dict()
    
    @APMInstrumentation.trace_function(name='ProductService.get_product')
    def get_product(self, product_id: int) -> Optional[Dict]:
        """Get product by ID."""
        product = self.db.Product.query.get(product_id)
        return product.to_dict() if product else None
    
    @APMInstrumentation.trace_function(name='ProductService.search_products')
    def search_products(self, query: str = None, category: str = None,
                       min_price: float = None, max_price: float = None) -> List[Dict]:
        """Search products with filters."""
        with APMInstrumentation.trace_block('product_search_query', 'db.query'):
            q = self.db.Product.query
            
            if query:
                q = q.filter(self.db.Product.name.ilike(f'%{query}%'))
            if category:
                q = q.filter(self.db.Product.category == category)
            if min_price is not None:
                q = q.filter(self.db.Product.price >= min_price)
            if max_price is not None:
                q = q.filter(self.db.Product.price <= max_price)
            
            products = q.all()
        
        APMInstrumentation.tag_transaction(
            search_results_count=len(products),
            search_query=query or '',
        )
        
        return [p.to_dict() for p in products]
    
    @APMInstrumentation.trace_function(name='ProductService.update_stock')
    def update_stock(self, product_id: int, quantity_change: int) -> Optional[Dict]:
        """Update product stock."""
        product = self.db.Product.query.with_for_update().get(product_id)
        if not product:
            return None
        
        product.stock += quantity_change
        if product.stock < 0:
            raise ValueError(f"Insufficient stock for product {product_id}")
        
        self.db.session.commit()
        return product.to_dict()


class OrderService:
    """Order service with APM instrumentation."""
    
    def __init__(self, db):
        self.db = db
        self.product_service = ProductService(db)
    
    @APMInstrumentation.trace_function(name='OrderService.create_order')
    def create_order(self, user_id: int, items: List[Dict]) -> Dict:
        """Create a new order with items."""
        
        # Validate user exists
        with APMInstrumentation.trace_block('validate_user', 'validation'):
            user = self.db.User.query.get(user_id)
            if not user:
                raise ValueError(f"User {user_id} not found")
        
        # Calculate total and validate stock
        total_amount = 0.0
        order_items = []
        
        with APMInstrumentation.trace_block('validate_and_calculate', 'business_logic'):
            for item_data in items:
                product = self.db.Product.query.get(item_data['product_id'])
                if not product:
                    raise ValueError(f"Product {item_data['product_id']} not found")
                
                if product.stock < item_data['quantity']:
                    raise ValueError(
                        f"Insufficient stock for {product.name}: "
                        f"requested {item_data['quantity']}, available {product.stock}"
                    )
                
                unit_price = product.price
                total_amount += unit_price * item_data['quantity']
                order_items.append({
                    'product': product,
                    'quantity': item_data['quantity'],
                    'unit_price': unit_price,
                })
        
        # Create order and items
        with APMInstrumentation.trace_block('create_order_records', 'db.write'):
            order = self.db.Order(
                user_id=user_id,
                total_amount=round(total_amount, 2),
                status='confirmed',
            )
            self.db.session.add(order)
            self.db.session.flush()  # Get order ID
            
            for item_info in order_items:
                order_item = self.db.OrderItem(
                    order_id=order.id,
                    product_id=item_info['product'].id,
                    quantity=item_info['quantity'],
                    unit_price=item_info['unit_price'],
                )
                self.db.session.add(order_item)
                
                # Update stock
                item_info['product'].stock -= item_info['quantity']
            
            self.db.session.commit()
        
        # Tag transaction with order details
        APMInstrumentation.tag_transaction(
            order_id=order.id,
            order_total=order.total_amount,
            items_count=len(order_items),
        )
        
        return order.to_dict()
    
    @APMInstrumentation.trace_function(name='OrderService.get_order')
    def get_order(self, order_id: int) -> Optional[Dict]:
        """Get order by ID."""
        order = self.db.Order.query.get(order_id)
        return order.to_dict() if order else None
    
    @APMInstrumentation.trace_function(name='OrderService.get_user_orders')
    def get_user_orders(self, user_id: int) -> List[Dict]:
        """Get all orders for a user."""
        orders = self.db.Order.query.filter_by(user_id=user_id).order_by(
            self.db.Order.created_at.desc()
        ).all()
        return [o.to_dict() for o in orders]
    
    @APMInstrumentation.trace_function(name='OrderService.get_analytics')
    def get_analytics(self, days: int = 30) -> Dict:
        """Get order analytics - demonstrates complex queries."""
        from sqlalchemy import func
        
        cutoff_date = datetime.utcnow() - timedelta(days=days)
        
        with APMInstrumentation.trace_block('analytics_queries', 'db.analytics'):
            # Total orders and revenue
            stats = self.db.session.query(
                func.count(self.db.Order.id).label('total_orders'),
                func.sum(self.db.Order.total_amount).label('total_revenue'),
                func.avg(self.db.Order.total_amount).label('avg_order_value'),
            ).filter(
                self.db.Order.created_at >= cutoff_date
            ).first()
            
            # Orders by status
            status_breakdown = self.db.session.query(
                self.db.Order.status,
                func.count(self.db.Order.id).label('count'),
            ).filter(
                self.db.Order.created_at >= cutoff_date
            ).group_by(self.db.Order.status).all()
            
            # Top products
            top_products = self.db.session.query(
                self.db.Product.name,
                func.sum(self.db.OrderItem.quantity).label('total_sold'),
                func.sum(
                    self.db.OrderItem.quantity * self.db.OrderItem.unit_price
                ).label('revenue'),
            ).join(
                self.db.OrderItem,
                self.db.Product.id == self.db.OrderItem.product_id
            ).join(
                self.db.Order,
                self.db.Order.id == self.db.OrderItem.order_id
            ).filter(
                self.db.Order.created_at >= cutoff_date
            ).group_by(
                self.db.Product.name
            ).order_by(
                func.sum(self.db.OrderItem.quantity).desc()
            ).limit(10).all()
        
        analytics = {
            'period_days': days,
            'total_orders': stats.total_orders or 0,
            'total_revenue': round(float(stats.total_revenue or 0), 2),
            'avg_order_value': round(float(stats.avg_order_value or 0), 2),
            'status_breakdown': {
                row.status: row.count for row in status_breakdown
            },
            'top_products': [
                {
                    'name': row.name,
                    'total_sold': row.total_sold,
                    'revenue': round(float(row.revenue), 2),
                }
                for row in top_products
            ],
        }
        
        APMInstrumentation.tag_transaction(
            analytics_period=days,
            total_orders=analytics['total_orders'],
        )
        
        return analytics


# =============================================================================
# Route Definitions
# =============================================================================

def _register_routes(app: Flask, db: SQLAlchemy):
    """Register API routes."""
    
    user_service = UserService(db)
    product_service = ProductService(db)
    order_service = OrderService(db)
    
    # Health check
    @app.route('/health')
    def health_check():
        """Health check endpoint."""
        apm_status = 'connected'
        try:
            client = elasticapm.get_client()
            if client:
                apm_status = 'connected' if not client._transport._closed else 'disconnected'
        except Exception:
            apm_status = 'unknown'
        
        return jsonify({
            'status': 'healthy',
            'timestamp': datetime.utcnow().isoformat(),
            'apm_status': apm_status,
            'service': APMConfig.SERVICE_NAME,
            'version': APMConfig.SERVICE_VERSION,
            'environment': APMConfig.ENVIRONMENT,
        })
    
    # User endpoints
    @app.route('/api/users', methods=['POST'])
    def create_user():
        """Create a new user."""
        data = request.get_json()
        if not data or 'username' not in data or 'email' not in data:
            return jsonify({'error': 'username and email are required'}), 400
        
        try:
            user = user_service.create_user(data['username'], data['email'])
            return jsonify(user), 201
        except Exception as e:
            elasticapm.capture_exception()
            return jsonify({'error': str(e)}), 400
    
    @app.route('/api/users/<int:user_id>')
    def get_user(user_id):
        """Get user by ID."""
        user = user_service.get_user(user_id)
        if user:
            return jsonify(user)
        return jsonify({'error': 'User not found'}), 404
    
    @app.route('/api/users')
    def list_users():
        """List users."""
        page = request.args.get('page', 1, type=int)
        per_page = request.args.get('per_page', 20, type=int)
        result = user_service.list_users(page=page, per_page=per_page)
        return jsonify(result)
    
    # Product endpoints
    @app.route('/api/products', methods=['POST'])
    def create_product():
        """Create a new product."""
        data = request.get_json()
        if not data or 'name' not in data or 'price' not in data:
            return jsonify({'error': 'name and price are required'}), 400
        
        try:
            product = product_service.create_product(
                name=data['name'],
                price=data['price'],
                stock=data.get('stock', 0),
                category=data.get('category'),
            )
            return jsonify(product), 201
        except Exception as e:
            elasticapm.capture_exception()
            return jsonify({'error': str(e)}), 400
    
    @app.route('/api/products/<int:product_id>')
    def get_product(product_id):
        """Get product by ID."""
        product = product_service.get_product(product_id)
        if product:
            return jsonify(product)
        return jsonify({'error': 'Product not found'}), 404
    
    @app.route('/api/products/search')
    def search_products():
        """Search products."""
        result = product_service.search_products(
            query=request.args.get('q'),
            category=request.args.get('category'),
            min_price=request.args.get('min_price', type=float),
            max_price=request.args.get('max_price', type=float),
        )
        return jsonify({'products': result, 'count': len(result)})
    
    # Order endpoints
    @app.route('/api/orders', methods=['POST'])
    def create_order():
        """Create a new order."""
        data = request.get_json()
        if not data or 'user_id' not in data or 'items' not in data:
            return jsonify({'error': 'user_id and items are required'}), 400
        
        try:
            order = order_service.create_order(
                user_id=data['user_id'],
                items=data['items'],
            )
            return jsonify(order), 201
        except ValueError as e:
            return jsonify({'error': str(e)}), 400
        except Exception as e:
            elasticapm.capture_exception()
            return jsonify({'error': str(e)}), 500
    
    @app.route('/api/orders/<int:order_id>')
    def get_order(order_id):
        """Get order by ID."""
        order = order_service.get_order(order_id)
        if order:
            return jsonify(order)
        return jsonify({'error': 'Order not found'}), 404
    
    @app.route('/api/users/<int:user_id>/orders')
    def get_user_orders(user_id):
        """Get orders for a user."""
        orders = order_service.get_user_orders(user_id)
        return jsonify({'orders': orders, 'count': len(orders)})
    
    # Analytics endpoint
    @app.route('/api/analytics')
    def get_analytics():
        """Get order analytics."""
        days = request.args.get('days', 30, type=int)
        analytics = order_service.get_analytics(days=days)
        return jsonify(analytics)
    
    # Diagnostic endpoints
    @app.route('/api/debug/slow')
    def slow_endpoint():
        """Intentionally slow endpoint for testing APM alerting."""
        delay = request.args.get('delay', 2.0, type=float)
        
        with APMInstrumentation.trace_block('intentional_delay', 'test.delay'):
            time.sleep(min(delay, 10.0))  # Cap at 10 seconds
        
        APMInstrumentation.tag_transaction(
            test_endpoint=True,
            delay_seconds=delay,
        )
        
        return jsonify({
            'message': f'Response delayed by {delay} seconds',
            'purpose': 'APM slow request detection test',
        })
    
    @app.route('/api/debug/error')
    def error_endpoint():
        """Intentionally erroring endpoint for testing APM error tracking."""
        error_type = request.args.get('type', 'runtime')
        
        APMInstrumentation.tag_transaction(test_endpoint=True)
        
        if error_type == 'value':
            raise ValueError("Test ValueError for APM error tracking")
        elif error_type == 'key':
            raise KeyError("Test KeyError for APM error tracking")
        elif error_type == 'type':
            raise TypeError("Test TypeError for APM error tracking")
        else:
            raise RuntimeError("Test RuntimeError for APM error tracking")
    
    @app.route('/api/debug/n-plus-one')
    def n_plus_one_endpoint():
        """Endpoint that demonstrates N+1 query problem for APM detection."""
        with APMInstrumentation.trace_block('n_plus_one_simulation', 'test.query'):
            users = db.User.query.all()
            result = []
            for user in users:
                # This creates N+1 queries - APM should capture all of them
                orders = user.orders.all()
                result.append({
                    'user': user.to_dict(),
                    'order_count': len(orders),
                })
        
        APMInstrumentation.tag_transaction(
            test_endpoint=True,
            n_plus_one_test=True,
            query_count=query_tracker.get_summary().get('total_queries', 0),
        )
        
        return jsonify({
            'users': result,
            'query_summary': query_tracker.get_summary(),
            'note': 'Check APM for N+1 query pattern detection',
        })
    
    @app.route('/api/debug/apm-info')
    def apm_info():
        """Get current APM configuration and status."""
        client = elasticapm.get_client()
        
        info = {
            'service_name': APMConfig.SERVICE_NAME,
            'service_version': APMConfig.SERVICE_VERSION,
            'environment': APMConfig.ENVIRONMENT,
            'server_url': APMConfig.SERVER_URL,
            'capture_body': APMConfig.CAPTURE_BODY,
            'capture_headers': APMConfig.CAPTURE_HEADERS,
            'transaction_sample_rate': APMConfig.TRANSACTION_SAMPLE_RATE,
            'collect_db_queries': APMConfig.COLLECT_DB_QUERIES,
            'client_active': client is not None,
        }
        
        return jsonify(info)


# =============================================================================
# Database Seed Data
# =============================================================================

def seed_database(app: Flask, db: SQLAlchemy):
    """Seed the database with sample data."""
    with app.app_context():
        db.create_all()
        
        # Check if data already exists
        if db.User.query.first():
            logger.info("Database already seeded.")
            return
        
        logger.info("Seeding database...")
        
        # Create users
        users = [
            db.User(username='alice', email='alice@example.com'),
            db.User(username='bob', email='bob@example.com'),
            db.User(username='charlie', email='charlie@example.com'),
            db.User(username='diana', email='diana@example.com'),
            db.User(username='eve', email='eve@example.com'),
        ]
        db.session.add_all(users)
        db.session.flush()
        
        # Create products
        products = [
            db.Product(name='Laptop Pro', price=1299.99, stock=50, category='Electronics'),
            db.Product(name='Wireless Mouse', price=29.99, stock=200, category='Electronics'),
            db.Product(name='USB-C Cable', price=12.99, stock=500, category='Accessories'),
            db.Product(name='Monitor 27"', price=449.99, stock=30, category='Electronics'),
            db.Product(name='Keyboard Mechanical', price=89.99, stock=100, category='Electronics'),
            db.Product(name='Webcam HD', price=69.99, stock=75, category='Electronics'),
            db.Product(name='Desk Lamp', price=34.99, stock=150, category='Office'),
            db.Product(name='Notebook Set', price=15.99, stock=300, category='Office'),
            db.Product(name='Headphones', price=199.99, stock=60, category='Electronics'),
            db.Product(name='Phone Stand', price=19.99, stock=250, category='Accessories'),
        ]
        db.session.add_all(products)
        db.session.flush()
        
        # Create sample orders
        import random
        
        for user in users:
            num_orders = random.randint(1, 3)
            for _ in range(num_orders):
                order_products = random.sample(products, random.randint(1, 4))
                total = 0
                
                order = db.Order(
                    user_id=user.id,
                    total_amount=0,
                    status=random.choice(['pending', 'confirmed', 'shipped', 'delivered']),
                    created_at=datetime.utcnow() - timedelta(
                        days=random.randint(0, 60),
                        hours=random.randint(0, 23),
                    ),
                )
                db.session.add(order)
                db.session.flush()
                
                for product in order_products:
                    qty = random.randint(1, 3)
                    item = db.OrderItem(
                        order_id=order.id,
                        product_id=product.id,
                        quantity=qty,
                        unit_price=product.price,
                    )
                    total += product.price * qty
                    db.session.add(item)
                
                order.total_amount = round(total, 2)
        
        db.session.commit()
        logger.info("Database seeded successfully.")


